import React from 'react';
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from '@/components/ui/card.tsx';
import { Button } from '@/components/ui/button.tsx';
import { Label } from '@/components/ui/label.tsx';
import { Separator } from '@/components/ui/separator.tsx';
import { ScrollArea } from '@/components/ui/scroll-area.tsx';
import { ShoppingCart } from 'lucide-react';

interface Product {
  id: string;
  name: string;
  description: string;
  price: number;
  imageUrl: string;
}

const products: Product[] = [
  {
    id: '1',
    name: 'Wireless Headphones',
    description: 'High-fidelity sound with noise cancellation.',
    price: 199.99,
    imageUrl: 'https://via.placeholder.com/150/0000FF/FFFFFF?text=Headphones',
  },
  {
    id: '2',
    name: 'Smartwatch',
    description: 'Track your fitness and stay connected.',
    price: 149.99,
    imageUrl: 'https://via.placeholder.com/150/FF0000/FFFFFF?text=Smartwatch',
  },
  {
    id: '3',
    name: 'Portable Charger',
    description: 'Keep your devices charged on the go.',
    price: 35.00,
    imageUrl: 'https://via.placeholder.com/150/00FF00/FFFFFF?text=Charger',
  },
  {
    id: '4',
    name: 'Ergonomic Keyboard',
    description: 'Comfortable typing experience for long hours.',
    price: 89.99,
    imageUrl: 'https://via.placeholder.com/150/FFFF00/000000?text=Keyboard',
  },
  {
    id: '5',
    name: 'Gaming Mouse',
    description: 'Precision and speed for competitive gaming.',
    price: 59.99,
    imageUrl: 'https://via.placeholder.com/150/00FFFF/000000?text=Mouse',
  },
];

const ItemPage: React.FC = () => {
  return (
    <div className="container mx-auto p-4">
      <h1 className="text-3xl font-bold mb-6">Our Products</h1>
      <Separator className="mb-6" />
      <ScrollArea className="h-[calc(100vh-150px)] w-full pr-4">
        <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-6">
          {products.map((product) => (
            <Card key={product.id} className="flex flex-col">
              <CardHeader className="p-0">
                <img src={product.imageUrl} alt={product.name} className="w-full h-48 object-cover rounded-t-lg" />
              </CardHeader>
              <CardContent className="flex-grow p-4">
                <CardTitle className="text-lg font-semibold mb-2">{product.name}</CardTitle>
                <CardDescription className="text-sm text-gray-600 mb-3 line-clamp-2">
                  {product.description}
                </CardDescription>
                <Label className="text-xl font-bold text-primary">${product.price.toFixed(2)}</Label>
              </CardContent>
              <CardFooter className="p-4 pt-0">
                <Button className="w-full">
                  <ShoppingCart className="mr-2 h-4 w-4" /> Add to Cart
                </Button>
              </CardFooter>
            </Card>
          ))}
        </div>
      </ScrollArea>
    </div>
  );
};

export default ItemPage;
